import{_ as o,o as t,c as a,an as r}from"./chunks/framework.Bj2qywlI.js";const f=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":null}'),i={name:"release-notes.md"};function n(s,e,d,l,c,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="Release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#Release-notes" aria-label="Permalink to &quot;Release notes {#Release-notes}&quot;">​</a></h1><p>LoweredDistributions.jl follows a hybrid changelog approach:</p><ul><li><p><strong>GitHub Releases</strong>: All releases (automatically generated by TagBot)</p></li><li><p><strong>NEWS.md</strong>: Major releases requiring detailed context (shown below)</p></li></ul><p>See <a href="https://github.com/EpiAware/LoweredDistributions.jl/releases" target="_blank" rel="noreferrer">GitHub Releases</a> for minor/patch release information.</p><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><ul><li><p><strong>fix:</strong> one-argument <code>lower(d)</code> is now AD-stable on the Erlang path (#73). <code>ChainStage</code> carries its rate&#39;s element type through <code>Coxian</code> and <code>PhaseType</code>, so the <code>c² ≤ 1</code> Erlang lowering differentiates on every backend (previously only Enzyme, through its native <code>Float64</code> tracking; ForwardDiff, ReverseDiff and Mooncake hit the concrete <code>Float64</code> rate field). And <code>lower(d::Gamma)</code>&#39;s over-dispersed arm builds the hyperexponential <code>PhaseType</code> directly rather than through <code>phase_type</code>, removing a <code>Union</code> return that broke Enzyme&#39;s type analysis. Differentiating <code>lower(d)</code> needs the Gamma shape (phase count) held constant — the fitting invariant that the phase count is fixed structure — so the docs no longer warn against the one-argument form on a differentiated path.</p></li><li><p><strong>feat:</strong> this package now hosts the ModifiedDistributions lowering bridge (#51/#23): a <code>ModifiedDistributions</code> weakdep and <code>LoweredDistributionsModifiedDistributionsExt</code> define <code>lower</code> for the modifier leaves, moved verbatim from ModifiedDistributions&#39; own (now removed) reverse extension. The bridge is partial by mathematical necessity: <code>Affine</code> (pure positive rescaling) and a <code>Modified</code> Exponential leaf lower exactly, while <code>Weighted</code>, a shifted <code>Affine</code>, <code>Transformed</code>, and a <code>Modified</code> non-Exponential or non-analytic-link leaf are refused with an explicit <code>ArgumentError</code> rather than a silent approximation. The hub-owned ownership split puts the Spec/generator knowledge here rather than in ModifiedDistributions; functionality is unchanged when both packages are loaded together.</p></li><li><p><strong>feat:</strong> this package now hosts the ComposedDistributions lowering bridge (#51/#22): a <code>ComposedDistributions</code> weakdep and <code>LoweredDistributionsComposedDistributionsExt</code> define <code>lower</code> for the composer types (<code>Sequential</code>, <code>Resolve</code>, <code>Compete</code>, <code>Shared</code> fold to a phase-type; <code>Parallel</code> and <code>Choose</code> fold to a joint CTMC), moved verbatim from ComposedDistributions&#39; own (now removed) reverse extension. The hub-owned ownership split puts the Spec/generator knowledge here rather than in ComposedDistributions; functionality is unchanged when both packages are loaded together.</p></li></ul><p>This file tracks notes for major releases and significant milestones; GitHub Releases (auto-generated from merged PRs) cover every release in between.</p>',7)])])}const u=o(i,[["render",n]]);export{f as __pageData,u as default};
